var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SMILE_NPC_OZ_C","text":{"KOREA":"용서? 용서 못하면 어쩔 건데?","JPN":"許さない？　許さなかったらどうするんだ？","ENG":"Forgive? What if we don’t need you to forgive us?","TWN":"不客氣？你不客氣是能怎樣？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_C","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SMILE_NPC_OZ_B","text":{"KOREA":"얘들이 세상 물정을 모르네. 이럴 땐 <color=#ffd34c>용서해 주세요</color>라고 해야지.","JPN":"世間知らずのガキしかいないな。\\nこんな時は<color=#ffd34c>許してください</color>って言わないと。","ENG":"These kids don’t know how this world works. You’re supposed to say <color=#ffd34c>“ please forgive us”</color> in this situation.","TWN":"這群小鬼沒見過壞人是吧？這種時候不是應該<color=#ffd34c>求饒</color>嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_C","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"목줄……","JPN":"リード……","ENG":"The leash...","TWN":"我要……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"풀어 버릴 거야.","JPN":"外すんだから。","ENG":"I’m gonna take it off.","TWN":"解開項圈！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"리온…….","JPN":"リオン……","ENG":"Liona...","TWN":"萊恩……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"수아랑…… 같이 기다리고 있어.","JPN":"コトリちゃんと……一緒に待っててね。","ENG":"Wait here with Skia.","TWN":"你和蘇亞……乖乖等我，"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"금방 다녀올게.","JPN":"すぐ戻るから。","ENG":"I’ll be back soon.","TWN":"我很快就回來。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"수아랑…… 같이 기다리고 있어.","JPN":"コトリちゃんと……一緒に待っててね。","ENG":"Wait here with Skia.","TWN":"你和蘇亞……乖乖等我，"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"금방 다녀올게.","JPN":"すぐ戻るから。","ENG":"I’ll be back soon.","TWN":"我很快就回來。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"네가 우릴 지켜줬던 그때처럼…… 말이지.","JPN":"君が私たちを守ってくれたあの日のように……ね。","ENG":"Just like how you protected us back then...","TWN":"這是你那時候……跟我們說過的話吧？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"괜찮겠어……?","JPN":"大丈夫そう……？","ENG":"Are you sure?","TWN":"沒關係嗎……？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"도로시 너에 비하면 이건 아무것도 아닌걸.","JPN":"ドロシーちゃん、あなたがやってくれたことに比べれば、なんてことないよ。","ENG":"It’s nothing compared to you, Dorothy.","TWN":"和你比起來，這根本不算什麼。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"겁쟁이를 지켜주는 건 언제나 네 몫이었잖아.","JPN":"臆病者を守ってあげるのは、いつもあなたの役目だったじゃない。","ENG":"You always stood up for the scaredy-cats.","TWN":"每次都是你在保護膽小鬼的不是嗎！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"날 지켜줄 때마다 네가 했을 생각, 마음들. 덕분에 조금이나마 느낄 수 있었어.","JPN":"私を守ってくれるたびにあなたがしてきたこと、その気持ち。\\nおかげで少しでも感じることができたの。","ENG":"The thoughts you would have had and the feelings you would have felt whenever you protected me... I got to experience those at least a bit.","TWN":"因為這樣，也讓我可以稍微體會到，你每次為我挺身而出時的心情。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그래서…… 이번 한 번쯤은 나도 힘낼 수 있겠다고 생각했던 거지.","JPN":"それで……私だって一度くらいはやれると思ったの。","ENG":"So... I thought that I could be brave at least that one time.","TWN":"所以……我才認為我是可以勇敢的！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"리온…….","JPN":"リオン……","ENG":"Liona...","TWN":"萊恩……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"이번에도 걱정 없어. 몇 번이라도 더 할 수 있을 것 같아.","JPN":"今回も心配ないよ。何度でもやれる気がするの。","ENG":"I’m not afraid this time as well. I think I could do this as many times as I need to.","TWN":"這次我也不擔心，我相信未來我也可以持續勇敢！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그게 너희를 지키는 일이니까. 평생도 할 수 있어.","JPN":"それであなたたちを守れるなら。この先、一生でもできるよ。","ENG":"Because it’s to protect you guys. I could do this forever.","TWN":"因為你們使我勇敢，我可以為你們勇敢一輩子！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그러니까 도로시.","JPN":"だからね、ドロシーちゃん。","ENG":"So... Dorothy.","TWN":"所以桃樂絲，"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그때 못해준 칭찬…… 이번에는 꼭 해주는 거다?","JPN":"あの時聞けなかった褒め言葉……\\n今度こそ絶対聞かせてね。","ENG":"The praise you couldn’t give me that time... Promise me that you’ll give it to me this time, okay?","TWN":"上次你欠我的稱讚……這次一定要記得喔！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"사람을 물지 않게 하려고 노력했는데…….","JPN":"人を噛まないようにしようと頑張ってきたけど……","ENG":"I tried my best to stop him from biting people...","TWN":"我一直很努力不讓托托咬人……"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"너흰 사람이 아닌 것 같아.","JPN":"あなたたちは人らしくないと思うの。","ENG":"But I don’t think you’re people.","TWN":"不過你們根本不是人，"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그러니까, 토토가 물어도 괜찮지 않을까?","JPN":"だから、トトが噛んでもいいんじゃないかな？","ENG":"So, it should be fine if Toto bites you guys, right?","TWN":"讓托托咬幾口應該也沒差吧？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SMILE_NPC_OZ_C","text":{"KOREA":"얘가 지금 무슨 헛소리를 하고 있는 거야?","JPN":"こいつ、何をほざいてんだ？","ENG":"What kind of nonsense is she saying?","TWN":"你現在是在嚇唬我們嗎？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SMILE_NPC_OZ_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SMILE_NPC_OZ_B","text":{"KOREA":"봐주는 것도 이제 끝이야! 한 번에 달려들어!!","JPN":"大目に見てやるのも終わりだ！　全員、一斉にかかれ！！","ENG":"Enough going easy on you! Everybody rush at her all at once!","TWN":"真是不知好歹！全都給我上！！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"토토…… 자, 잘 부탁해……!","JPN":"トト……よ、よろしくね……！","ENG":"Toto, d-do your thing!","TWN":"托托……拜託你囉……！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};